import{c as a,Q as d,j as t,m as s}from"./chunks/framework.DVkeSyfh.js";const m=JSON.parse('{"title":"Поиск и запись тегов","description":"","frontmatter":{},"headers":[],"relativePath":"ru/search-and-tags.md","filePath":"ru/search-and-tags.md","lastUpdated":1780252792000}'),o={name:"ru/search-and-tags.md"};function c(i,e,l,r,n,p){return d(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="поиск-и-запись-тегов" tabindex="-1">Поиск и запись тегов <a class="header-anchor" href="#поиск-и-запись-тегов" aria-label="Permalink to &quot;Поиск и запись тегов&quot;">​</a></h1><p>Эта страница описывает вкладки поиска, поверхность фильтрации по классификаторам и явный процесс записи жанровых тегов. Используйте её, когда библиотека уже просканирована и нужно найти подходящих соседей, собрать временный сет или решить, стоит ли сохранять жанры MAEST обратно в файлы.</p><h2 id="режимы-поиска" tabindex="-1">Режимы поиска <a class="header-anchor" href="#режимы-поиска" aria-label="Permalink to &quot;Режимы поиска&quot;">​</a></h2><p>Панель поиска состоит из отдельных вкладок.</p><p>Выбирайте вкладку по своей задаче:</p><table tabindex="0"><thead><tr><th>Вкладка</th><th>Что делает</th><th>Когда использовать</th></tr></thead><tbody><tr><td>SONARA</td><td>Ищет по объяснимым признакам плейлиста и пользовательским mixer weights.</td><td>Нужны кандидаты для DJ-перехода и контроль над rhythm, tempo, timbre, dynamics или harmonic balance.</td></tr><tr><td>MERT</td><td>Ищет от выбранных seed-треков в embedding-пространстве MERT.</td><td>Нужна похожесть по аудиомодели без настройки весов признаков.</td></tr><tr><td>CLAP</td><td>Ищет по embedding-ам аудио CLAP на основе текстового запроса.</td><td>Вы знаете нужное звучание или настроение, но seed-трека нет.</td></tr><tr><td>CLASS</td><td>Фильтрует по оценкам продвинутых классификаторов.</td><td>Нужен переиспользуемый персональный сигнал, обученный в Rhythm Lab.</td></tr></tbody></table><p>В браузере библиотеки также есть фильтр-пресет <code>syncopated</code>. Он выбирает треки, у которых сохранённые метаданные MAEST содержат <code>maest_syncopated_rhythm = true</code>, и может комбинироваться с обычным текстовым поиском по библиотеке и процессом add-filtered-tracks. У каждой строки библиотеки есть кнопка-сердечко для локального списка понравившихся треков. Фильтр-сердечко в элементах управления библиотекой показывает только понравившиеся треки в том же постраничном браузере и может комбинироваться с текстовым поиском, пресетом <code>syncopated</code>, фильтрами по оценкам классификаторов и процессом add-filtered-tracks. Элементы управления библиотекой включают кнопку переключения <code>LIKE</code> / <code>FTS</code>. <code>LIKE</code> — режим по умолчанию: substring search по artist, title, album, path и metadata. <code>FTS</code> использует token-based SQLite FTS5 index. Он может намного быстрее считать или сужать token matches, но не ищет произвольные подстроки внутри одного token, а очень частые token всё ещё могут тратить заметное время на сортировку первой страницы в library order. Процесс add-filtered-tracks использует выбранный search mode. Элементы управления библиотекой также включают кнопку направления сортировки, которая разворачивает текущую загруженную страницу в браузере без изменения backend-запроса или порядка, хранящегося в базе данных. Элементы пагинации расположены слева в элементах управления библиотекой, после кнопок фильтров. Справа показан общий счётчик для текущего вида библиотеки, а за ним — кнопки направления сортировки и add-visible-tracks. Общий счётчик и счётчик страниц отражают активный текстовый поиск, search mode, пресет, фильтр понравившихся и фильтры по оценкам классификаторов.</p><p>Вкладка CLASS содержит элементы управления классификаторами, обнаруженные из metadata продвинутых моделей <code>models/classifiers/*/model.json</code>. Ползунок каждого классификатора фильтрует библиотеку и add-filtered-tracks workflow по <code>track_classifier_scores.score</code>. Сам scoring классификаторов запускается из основного блока анализа через галочку <code>CLASSIFIERS</code>, после любых выбранных аудиомоделей. Строки analysis model показывают coverage counts для SONARA, MAEST, MERT, CLAP и полного покрытия promoted-classifier score; верхний header оставляет только общее количество треков.</p><h3 id="поиск-sonara" tabindex="-1">Поиск SONARA <a class="header-anchor" href="#поиск-sonara" aria-label="Permalink to &quot;Поиск SONARA&quot;">​</a></h3><p>SONARA — основной объяснимый путь поиска по seed-трекам. Он отправляет выбранные seed-треки, лимит, минимальную похожесть, mixer weights и modifiers в <code>/api/search/sonara</code>.</p><p>Лимит результатов UI по умолчанию — <code>10</code>.</p><p>Mixer weights:</p><ul><li><code>timbre</code></li><li><code>rhythm</code></li><li><code>dynamics</code></li><li><code>harmonic</code></li><li><code>tempo</code></li></ul><p>Modifiers:</p><ul><li><code>energy</code></li><li><code>valence</code></li><li><code>acousticness</code></li><li><code>brightness</code></li><li><code>rhythm_density</code></li><li><code>dynamic_range</code></li><li><code>loudness</code></li></ul><p>Backend по-прежнему принимает имена пресетных режимов для совместимости:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>balanced, vibe, sound, dj_transition, custom</span></span></code></pre></div><p>Активный путь интерфейса использует пользовательский микшер.</p><p>Начинайте с SONARA, когда нужны объяснимые результаты. Увеличивайте или уменьшайте mixer weights, чтобы смещать поиск в сторону пригодности для перехода, ритмического ощущения, гармонической похожести или общего звучания.</p><h3 id="поиск-mert" tabindex="-1">Поиск MERT <a class="header-anchor" href="#поиск-mert" aria-label="Permalink to &quot;Поиск MERT&quot;">​</a></h3><p>Поиск MERT по seed-трекам отправляет seed-треки, лимит и необязательную минимальную похожесть в <code>/api/search</code>. Он ранжирует треки в embedding-пространстве MERT.</p><p>Лимит результатов UI и API по умолчанию — <code>10</code>.</p><p>Используйте MERT после команды <code>dj-sim analyze --models mert</code> или соответствующей выбранной модели анализа в интерфейсе. Если результаты пусты или устарели, проверьте, есть ли у треков-кандидатов embedding-и MERT.</p><h3 id="текстовыи-поиск-clap" tabindex="-1">Текстовый поиск CLAP <a class="header-anchor" href="#текстовыи-поиск-clap" aria-label="Permalink to &quot;Текстовый поиск CLAP&quot;">​</a></h3><p>Текстовый поиск CLAP отправляет текстовый запрос, лимит, необязательную минимальную похожесть и устройство в <code>/api/search/text</code>. Он ранжирует аудиовекторы CLAP относительно текстового вектора CLAP.</p><p>Лимит результатов UI и API по умолчанию — <code>10</code>.</p><p>Конкретные запросы на английском обычно работают лучше всего:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Melancholic minimal house with broken drums, warm chords, no vocals</span></span>
<span class="line"><span>Dark hypnotic techno with sparse percussion and deep rolling bass</span></span>
<span class="line"><span>Organic microhouse with soft pads, plucked textures, and spacious mood</span></span></code></pre></div><p>Используйте CLAP для исследовательского поиска. Включайте в запрос музыкальную фактуру, настроение, ощущение темпа, наличие вокала или инструментовку вместо того, чтобы полагаться только на название жанра.</p><h3 id="class-классификаторы" tabindex="-1">CLASS / классификаторы <a class="header-anchor" href="#class-классификаторы" aria-label="Permalink to &quot;CLASS / классификаторы&quot;">​</a></h3><p>Вкладка CLASS предназначена для рабочих процессов на основе классификаторов, а не для поиска по похожести. Она показывает продвинутые классификаторы, обнаруженные из <code>models/classifiers/*/model.json</code>:</p><ul><li>Ползунок каждого классификатора фильтрует библиотеку на стороне сервера по сохранённой оценке классификатора.</li><li>Диалог метаданных показывает сохранённые classifier scores ниже признаков SONARA.</li></ul><p>Продвинутые классификаторы требуют файла продвинутой модели и треков с полным набором признаков. Они не анализируют аудио напрямую. Выберите <code>CLASSIFIERS</code> в основном блоке анализа, чтобы запустить cancellable classifier jobs после любых выбранных audio models; сначала запустите SONARA, MERT и MAEST для треков, которые нужно оценить.</p><p>Используйте фильтры CLASS после оценки продвинутого классификатора. Высокая оценка означает, что модель считает трек соответствующим положительной метке профиля; это подсказка для рабочего процесса, а не гарантия.</p><h2 id="запись-тегов" tabindex="-1">Запись тегов <a class="header-anchor" href="#запись-тегов" aria-label="Permalink to &quot;Запись тегов&quot;">​</a></h2><p>Сохранение жанров MAEST записывает одну нормализованную строку жанров, разделённую точкой с запятой, например:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tech House; Minimal; Techno</span></span></code></pre></div><p>Префиксы категорий MAEST вроде <code>Electronic---</code> удаляются перед записью.</p><p>Поля жанра в зависимости от формата:</p><ul><li>ID3-теги MP3, WAV, AIFF: <code>TCON</code></li><li>FLAC и теги в стиле Vorbis: <code>GENRE</code></li><li>MP4, M4A, ALAC: <code>©gen</code></li></ul><p>Запись жанра в WAV использует поддержку <code>WAVE</code> в Mutagen, сохраняет значение <code>TCON</code> и проверяет, что сохранённое значение можно прочитать после записи. Она не выполняет пользовательский шаг восстановления RIFF. Если запись или обратное чтение WAV не удаётся, этот трек помечается как неуспешный, а пакет продолжается.</p><p>Используйте запись тегов только после проверки меток MAEST в приложении. Она предназначена для сохранения сгенерированных меток жанров в стандартное поле жанра; это не универсальный редактор метаданных, и его не следует использовать для изменения названия, исполнителя, альбома, BPM, тональности или пользовательских тегов.</p>`,42)])])}const u=a(o,[["render",c]]);export{m as __pageData,u as default};
